
# 정적비열(cp) 계산 함수
def cp_g(H2_V,N2_V,O2_V,CO_V,H2O_V,CO2_V,SO2_V,AIR_V,T_fg):
    CP_H2 =  -0.000000000002122 * T_fg**3 + 0.000000011394308 * T_fg**2 - 0.000003897019168 * T_fg + 0.310087114024427
    CP_N2 = -0.000000000000000 * T_fg**5 + 0.000000000000011 * T_fg**4 - 0.000000000037690 * T_fg**3 + 0.000000053405432 * T_fg**2 - 0.000002801728570 *T_fg + 0.310126789673120
    CP_O2 = 0.000000000002220 * T_fg**3 - 0.000000017692452 * T_fg**2 + 0.000055736827065 * T_fg + 0.309648266344587
    CP_CO = -0.000000000000000 * T_fg**5 + 0.000000000000012 * T_fg**4 - 0.000000000036213 * T_fg**3 + 0.000000044227785 * T_fg**2 + 0.000008769800556 * T_fg + 0.309744770956144
    CP_H2O =  0.000000000000002 * T_fg**4 - 0.000000000015851 * T_fg**3 + 0.000000032104253 *T_fg**2 + 0.000036286546599 * T_fg + 0.353789136621458
    CP_CO2 = -0.000000000000006 * T_fg**4 + 0.000000000045579 * T_fg**3 - 0.000000146053037 * T_fg**2 + 0.000252867868884 * T_fg + 0.382826461961884
    CP_SO2 =  -0.000000000000004 * T_fg**4 + 0.000000000036344 * T_fg**3 - 0.000000125257272 * T_fg**2 + 0.000217040030367 * T_fg + 0.424999633429877
    CP_AIR = -0.000000000000000 * T_fg**5 + 0.000000000000009 * T_fg**4 - 0.000000000032079 * T_fg**3 + 0.000000043655248 * T_fg**2 + 0.000005035508760 * T_fg + 0.310851377821763
    CP_fg = (CP_H2 * H2_V + CP_N2*N2_V + CP_O2*O2_V+CP_CO*CO_V+CP_H2O*H2O_V+CP_CO2*CO2_V+CP_SO2*SO2_V+CP_AIR*AIR_V)/100
    return CP_fg